function solve(nums) {
    // Constraints: nums[i] <= 10^5. We need to check slightly higher values.
    const MAX_VAL = 100100; 

    // 1. Sieve of Eratosthenes to precalculate primes
    const is_prime = new Array(MAX_VAL + 1).fill(true);
    is_prime[0] = is_prime[1] = false;

    for (let p = 2; p * p <= MAX_VAL; p++) {
        if (is_prime[p]) {
            for (let i = p * p; i <= MAX_VAL; i += p)
                is_prime[i] = false;
        }
    }

    let totalOperations = 0;
    const N = nums.length;

    // 2. Iterate through the array and calculate minimum operations
    for (let i = 0; i < N; i++) {
        const currentVal = nums[i];

        if (i % 2 === 0) {
            // Even index: Must be PRIME
            if (is_prime[currentVal]) {
                // Already prime, cost = 0
                continue;
            }

            // Find the smallest prime k >= currentVal
            let k = Math.max(currentVal, 2); // Ensure k starts at least at 2
            while (k <= MAX_VAL && !is_prime[k]) {
                k++;
            }

            if (k > MAX_VAL) {
                // This should theoretically not happen given the constraints and MAX_VAL choice, 
