                // For this problem context, we assume the target is reachable within MAX_VAL.
            }

            totalOperations += (k - currentVal);

        } else {
            // Odd index: Must be NON-PRIME (Composite or 1)

            // Check if currentVal is prime
            let currentIsPrime;
            if (currentVal <= 1) {
                currentIsPrime = false; // 1 is non-prime
            } else if (currentVal > MAX_VAL) {
                 // If input exceeds sieve limit, we rely on primality test for large numbers, 
