                 // Sticking strictly to constraints: currentVal <= 10^5, so sieve works.
            } else {
                currentIsPrime = is_prime[currentVal];
            }

            if (!currentIsPrime) {
                // Already non-prime, cost = 0
                continue;
            }

            // currentVal is prime. Find the smallest non-prime k >= currentVal.
            let k;
            if (currentVal === 2) {
                // 2 -> 3 (P) -> 4 (NP). Target k=4. Cost 2.
                k = 4;
            } else {
                // currentVal >= 3 (odd prime). currentVal + 1 is even and >= 4, hence composite/non-prime.
                k = currentVal + 1;
            }

            totalOperations += (k - currentVal);
        }
    }

    return totalOperations;
}

